export function parseRequestRandomnessInstruction<
  TProgram extends string,
  TAccountMetas extends readonly AccountMeta[],
>(
  instruction: Instruction<TProgram> &
    InstructionWithAccounts<TAccountMetas> &
    InstructionWithData<ReadonlyUint8Array>,
): ParsedRequestRandomnessInstruction<TProgram, TAccountMetas> {
  if (instruction.accounts.length < 9) {
    // TODO: Coded error.
    throw new Error("Not enough accounts");
  }
  let accountIndex = 0;
  const getNextAccount = () => {
    const accountMeta = (instruction.accounts as TAccountMetas)[accountIndex]!;
    accountIndex += 1;
    return accountMeta;
  };
  return {
    programAddress: instruction.programAddress,
    accounts: {
      raffleState: getNextAccount(),
      solRaffle: getNextAccount(),
      vrfFeeVault: getNextAccount(),
      vrf: getNextAccount(),
      clientState: getNextAccount(),
      client: getNextAccount(),
      networkState: getNextAccount(),
      treasury: getNextAccount(),
      systemProgram: getNextAccount(),
    },
    data: getRequestRandomnessInstructionDataDecoder().decode(instruction.data),
  };
}
